//! x86_64 permanent GDT + 64-bit TSS (Interrupt Stack Table) for `tb-hal`.
//!
//! Replaces the boot trampoline's transient GDT (`boot.rs`, `__boot_gdt64`) and
//! Firecracker's boot GDT with a PERMANENT flat 64-bit GDT plus a 64-bit TSS, so
//! the IDT (`idt.rs`) can route the double-fault, NMI and machine-check vectors
//! onto dedicated, known-good IST stacks. All `unsafe`/asm stays in `tb-hal`
//! (KERNEL-FOUNDATION-SPEC §1); the kernel crate is `#![forbid(unsafe_code)]`.
//!
//! Layout & descriptor bits are QUOTED from primary sources, not invented:
//!   * GDT segment descriptor — Access Byte (P,DPL,S,E,DC,RW,A) and Flags
//!     (G,DB,L): OSDev "Global Descriptor Table" == Intel SDM Vol.3A §3.4.5,
//!     Figure 3-8 "Segment Descriptor".
//!       - ring0 code : Access 0x9A (P=1,DPL=0,S=1,E=1,DC=0,RW=1,A=0); L=1.
//!       - ring0 data : Access 0x92 (P=1,DPL=0,S=1,E=0,DC=0,RW=1,A=0); DB=1.
//!   * 64-bit (Long Mode) TSS descriptor — 16 bytes, Access 0x89
//!     (P=1,DPL=0,S=0,Type=0x9 "64-bit TSS (Available)"), Base split across the
//!     low 8 bytes plus Base[63:32] in the high 8 bytes: OSDev "GDT" §"Long Mode
//!     System Segment Descriptor" == Intel SDM Vol.3A §7.2.3 / Figure 7-4
//!     "Format of TSS and LDT Descriptors in 64-Bit Mode".
//!   * 64-bit TSS body — RSP0..2, then IST1..7 (each a 64-bit stack pointer),
//!     then the 16-bit I/O-Map Base at byte 0x66; total 104 (0x68) bytes:
//!     OSDev "Task State Segment" §"Long Mode" == Intel SDM Vol.3A §7.7,
//!     Figure 7-11 "64-Bit TSS Format".

use core::arch::asm;
use core::mem::size_of;
use core::ptr::{addr_of, addr_of_mut};

/// GDT selectors: `index << 3 | TI(0) | RPL(0)`. Entry 1 = code, 2 = data,
/// 3..4 = the (16-byte) 64-bit TSS descriptor.
pub(super) const KERNEL_CODE_SEL: u16 = 0x08;
pub(super) const KERNEL_DATA_SEL: u16 = 0x10;
pub(super) const TSS_SEL: u16 = 0x18;

// Flat 64-bit descriptors (base 0, limit 0xFFFFF, page granularity). Base/limit
// are ignored by the CPU in 64-bit mode; the load-bearing bits are Access + L.
const NULL_DESC: u64 = 0x0000_0000_0000_0000;
const CODE_DESC: u64 = 0x00AF_9A00_0000_FFFF; // Access 0x9A, Flags G=1,L=1
const DATA_DESC: u64 = 0x00CF_9200_0000_FFFF; // Access 0x92, Flags G=1,DB=1

/// Access byte for an available 64-bit TSS descriptor: P=1, DPL=0, S=0,
/// Type=0x9 (Intel SDM Vol.3A §3.5, "64-bit TSS (Available)").
const TSS_ACCESS_AVAILABLE: u64 = 0x89;

/// Bytes per IST stack. 8 KiB is ample for the #DF / NMI / #MC handler chain
/// (handler + dispatch + hook + serial); multiple-of-16 keeps the top aligned.
const IST_STACK_SIZE: usize = 8 * 1024;

// 64-bit TSS as 26 dwords (104 bytes). Using u32 lanes (rather than a packed
// struct of u64s at 4-byte-aligned offsets) keeps every field naturally aligned
// so no `unaligned_references` hazard arises when we fill it through a pointer.
const TSS_DWORDS: usize = 26;
const TSS_IST1: usize = 0x24 / 4; // 9   — IST1 low dword (high is +1)
const TSS_IST2: usize = 0x2C / 4; // 11  — IST2
const TSS_IST3: usize = 0x34 / 4; // 13  — IST3
const TSS_IOPB: usize = 0x64 / 4; // 25  — I/O-Map Base lives in bits [31:16]

/// `lgdt`/`lidt` operand: 16-bit limit followed by the 64-bit linear base
/// (Intel SDM Vol.3A §2.4.1/§2.4.3; the m16&64 form). Packed = exactly 10 bytes.
#[repr(C, packed)]
pub(super) struct DescriptorPointer {
    pub(super) limit: u16,
    pub(super) base: u64,
}

#[repr(C)]
struct Tss {
    dwords: [u32; TSS_DWORDS],
}
impl Tss {
    const fn new() -> Self {
        Tss {
            dwords: [0; TSS_DWORDS],
        }
    }
}

#[repr(C, align(16))]
struct Gdt {
    entries: [u64; 5],
}

#[repr(C, align(16))]
#[derive(Clone, Copy)]
struct IstStack([u8; IST_STACK_SIZE]);

// Permanent tables. Zero-initialised, so they live in `.bss` (zeroed by
// `_start`); `init()` fills the live values at runtime through raw pointers.
static mut GDT: Gdt = Gdt { entries: [0; 5] };
static mut TSS: Tss = Tss::new();
static mut IST_STACKS: [IstStack; 3] = [IstStack([0; IST_STACK_SIZE]); 3];

/// Top-of-stack (highest, exclusive) address of IST stack `i` (0..3). Stacks
/// grow down; the array base is 16-aligned and each frame is a 16-multiple, so
/// the returned pointer is 16-aligned as the CPU expects.
unsafe fn ist_top(i: usize) -> u64 {
    let base = addr_of!(IST_STACKS) as u64;
    base + ((i + 1) * IST_STACK_SIZE) as u64
}

/// Build the two qwords of a 64-bit (Long Mode) TSS descriptor for `base`/
/// `limit`. Bit positions per Intel SDM Vol.3A Figure 7-4 / OSDev "GDT".
fn tss_descriptor(base: u64, limit: u32) -> (u64, u64) {
    let limit = limit as u64;
    let low = (limit & 0xFFFF)                       // Limit[15:0]
        | ((base & 0x00FF_FFFF) << 16)               // Base[23:0]
        | (TSS_ACCESS_AVAILABLE << 40)               // Access byte (0x89)
        | (((limit >> 16) & 0xF) << 48)              // Limit[19:16]
        // Flags nibble [55:52] = 0 (G=0 byte-granular, AVL=0)
        | (((base >> 24) & 0xFF) << 56); // Base[31:24]
    let high = (base >> 32) & 0xFFFF_FFFF; // Base[63:32]; high dword reserved (0)
    (low, high)
}

/// Install the permanent GDT + TSS: fill the IST tops, encode the TSS
/// descriptor at the runtime address of `TSS`, `lgdt`, reload CS + data
/// segments, and `ltr`. Called once from `super::install_traps()`.
pub(super) fn init() {
    unsafe {
        // 1. Fill the TSS: IST1..3 tops + disable the I/O permission bitmap
        //    (I/O-Map Base == sizeof(TSS) puts it past the segment limit).
        let tss = addr_of_mut!(TSS) as *mut u32;
        let s1 = ist_top(0);
        let s2 = ist_top(1);
        let s3 = ist_top(2);
        *tss.add(TSS_IST1) = s1 as u32;
        *tss.add(TSS_IST1 + 1) = (s1 >> 32) as u32;
        *tss.add(TSS_IST2) = s2 as u32;
        *tss.add(TSS_IST2 + 1) = (s2 >> 32) as u32;
        *tss.add(TSS_IST3) = s3 as u32;
        *tss.add(TSS_IST3 + 1) = (s3 >> 32) as u32;
        *tss.add(TSS_IOPB) = (size_of::<Tss>() as u32) << 16;

        // 2. Build the GDT: null, code, data, TSS descriptor (2 entries).
        let tss_base = addr_of!(TSS) as u64;
        let tss_limit = (size_of::<Tss>() - 1) as u32;
        let (tss_lo, tss_hi) = tss_descriptor(tss_base, tss_limit);
        let gdt = addr_of_mut!(GDT) as *mut u64;
        *gdt.add(0) = NULL_DESC;
        *gdt.add(1) = CODE_DESC;
        *gdt.add(2) = DATA_DESC;
        *gdt.add(3) = tss_lo;
        *gdt.add(4) = tss_hi;

        // 3. Load it and reload the segment registers / task register.
        let gdtr = DescriptorPointer {
            limit: (size_of::<Gdt>() - 1) as u16,
            base: addr_of!(GDT) as u64,
        };
        load_gdt_and_segments(addr_of!(gdtr));
    }
}

/// `lgdt` the new table, far-return to reload CS with the ring0 code selector
/// (loading an L=1 CS under EFER.LME|CR0.PG keeps us in 64-bit mode), reload
/// the data segments, then `ltr` the TSS selector.
///
/// (a) PRE: 64-bit long mode, `gdtr` points at a valid `DescriptorPointer`
///     whose GDT has compatible 0x08 code / 0x10 data and a 0x18 64-bit TSS.
///     POST: CS=0x08, DS/ES/SS/FS/GS=0x10, TR=0x18 against the new GDT.
/// (b) ABI: Intel syntax (Rust default). Uses the stack (push/`retfq`, balanced
///     so RSP nets zero); clobbers segment regs + scratch regs + flags; reads
///     the descriptor from memory. Sources: Intel SDM Vol.3A §2.4.1 (lgdt),
///     §3.4.3/§5.8.1 (CS reload / far transfer), §7.3 `ltr`; OSDev GDT Tutorial.
/// (c) Tested by: kernel M1 sequence (a #BP must dispatch + resume afterwards).
#[inline]
unsafe fn load_gdt_and_segments(gdtr: *const DescriptorPointer) {
    asm!(
        "lgdt [{gdtr}]",
        // Reload CS via a far return to label 2: push CS, push target RIP, retfq.
        "push {code}",
        "lea {tmp}, [rip + 2f]",
        "push {tmp}",
        "retfq",
        "2:",
        // Reload the data/stack segment registers with the ring0 data selector.
        "mov ds, {data:x}",
        "mov es, {data:x}",
        "mov ss, {data:x}",
        "mov fs, {data:x}",
        "mov gs, {data:x}",
        // Load the task register with the TSS selector (activates the IST).
        "ltr {tss:x}",
        gdtr = in(reg) gdtr,
        code = in(reg) KERNEL_CODE_SEL as u64,
        data = in(reg) KERNEL_DATA_SEL as u64,
        tss  = in(reg) TSS_SEL as u64,
        tmp  = lateout(reg) _,
    );
}

//! x86_64 IDT: 256 64-bit interrupt-gate descriptors pointing at the per-vector
//! thunks in `trap.rs`. All `unsafe`/asm stays in `tb-hal`; the kernel crate is
//! `#![forbid(unsafe_code)]` (KERNEL-FOUNDATION-SPEC §1).
//!
//! Descriptor bits are QUOTED from primary sources, not invented:
//!   * 64-bit IDT gate descriptor — 16 bytes laid out offset_low(16) /
//!     selector(16) / ist(8, bits[2:0]) / type_attr(8) / offset_mid(16) /
//!     offset_high(32) / reserved(32); `type_attr = 0x8E` means P=1, DPL=0,
//!     Type=0xE "64-bit Interrupt Gate": OSDev "Interrupt Descriptor Table"
//!     §"Structure on x86-64" == Intel SDM Vol.3A §6.14.1, Figure 6-8
//!     "64-Bit IDT Gate Descriptors".
//!   * IST field selects a Task-State-Segment stack (0 = none); we route #DF
//!     (vector 8) -> IST1, NMI (2) -> IST2, #MC (18) -> IST3 onto the stacks set
//!     up in `gdt.rs`: Intel SDM Vol.3A §6.14.5 "Interrupt Stack Table".

use core::arch::asm;
use core::mem::size_of;
use core::ptr::{addr_of, addr_of_mut};

use super::gdt::{DescriptorPointer, KERNEL_CODE_SEL};
use super::trap;

/// One 64-bit IDT gate descriptor (16 bytes). Field order == on-wire layout.
#[repr(C)]
#[derive(Clone, Copy)]
#[allow(dead_code)] // fields are written, never read back by Rust
struct IdtEntry {
    offset_low: u16,
    selector: u16,
    ist: u8,
    type_attr: u8,
    offset_mid: u16,
    offset_high: u32,
    reserved: u32,
}
impl IdtEntry {
    const fn missing() -> Self {
        IdtEntry {
            offset_low: 0,
            selector: 0,
            ist: 0,
            type_attr: 0,
            offset_mid: 0,
            offset_high: 0,
            reserved: 0,
        }
    }

    /// Point this gate at `handler`, running on IST stack `ist` (0 = current
    /// stack). type_attr 0x8E == Present, DPL 0, 64-bit interrupt gate.
    fn set(&mut self, handler: u64, ist: u8) {
        self.offset_low = handler as u16;
        self.offset_mid = (handler >> 16) as u16;
        self.offset_high = (handler >> 32) as u32;
        self.selector = KERNEL_CODE_SEL;
        self.ist = ist & 0x7;
        self.type_attr = 0x8E;
        self.reserved = 0;
    }
}

#[repr(C, align(16))]
struct Idt {
    entries: [IdtEntry; 256],
}

// Zero-initialised -> `.bss` (zeroed by `_start`); `init()` fills it at runtime.
static mut IDT: Idt = Idt {
    entries: [IdtEntry::missing(); 256],
};

/// Build all 256 gates from the `trap.rs` thunk table, route the IST-backed
/// vectors, then `lidt`. Called once from `super::install_traps()` AFTER the
/// GDT/TSS are live (the IST indices reference TSS stacks `gdt.rs` installs).
pub(super) fn init() {
    unsafe {
        let entries = addr_of_mut!(IDT) as *mut IdtEntry;
        let mut v = 0usize;
        while v < 256 {
            let ist = match v {
                8 => 1,  // #DF  -> IST1
                2 => 2,  // NMI  -> IST2
                18 => 3, // #MC  -> IST3
                _ => 0,  // everything else: current stack
            };
            let mut entry = IdtEntry::missing();
            entry.set(trap::thunk(v), ist);
            core::ptr::write(entries.add(v), entry);
            v += 1;
        }

        let idtr = DescriptorPointer {
            limit: (size_of::<[IdtEntry; 256]>() - 1) as u16, // 256*16 - 1 = 4095
            base: addr_of!(IDT) as u64,
        };
        // (a) PRE: `idtr` describes a 256-entry IDT. POST: IDTR loaded.
        // (b) ABI: `lidt m16&64`; reads memory (readonly), no stack, no flags.
        //     Intel SDM Vol.3A §2.4.3 / §6.10. Intel syntax (Rust default).
        // (c) Tested by: kernel M1 sequence (a #BP must vector through this IDT).
        asm!(
            "lidt [{}]",
            in(reg) addr_of!(idtr),
            options(readonly, nostack, preserves_flags),
        );
    }
}

//! x86_64 trap entry: per-vector thunks + `__alltraps` + the extern "C"
//! `x86_trap_handler` that marshals a raw `TrapFrame` into a SAFE
//! [`crate::TrapInfo`] and hands policy to the registered hook
//! ([`crate::dispatch_trap`]). All `unsafe`/asm stays in `tb-hal`; the kernel
//! crate is `#![forbid(unsafe_code)]` (KERNEL-FOUNDATION-SPEC §1).
//!
//! Verified facts QUOTED from primary sources, not invented:
//!   * Error-code vectors. The CPU pushes a 32-bit error code only for #DF(8),
//!     #TS(10), #NP(11), #SS(12), #GP(13), #PF(14), #AC(17), #CP(21), #SX(30);
//!     every other vector gets a dummy 0 from the thunk so the frame is uniform:
//!     Intel SDM Vol.3A §6.13 + Table 6-1 "Protected-Mode Exceptions and
//!     Interrupts"; OSDev "Exceptions".
//!   * #BP (vector 3, INT3) is a TRAP: the CPU-saved RIP points to the
//!     instruction FOLLOWING int3, so `iretq` resumes with no RIP fix-up —
//!     Intel SDM Vol.3A §6.15 "#BP ... Saved Instruction Pointer points to the
//!     instruction following the INT3" (contrast aarch64 `brk`, whose ELR is AT
//!     the instruction and must be advanced by 4). #PF(14) fault address = CR2
//!     (Intel SDM Vol.3A §6.15 "#PF").
//!   * 64-bit interrupt entry aligns the stack to 16 bytes before pushing the
//!     iret frame (Intel SDM Vol.3A §6.14.2 "Stack Usage ... aligned to a
//!     16-byte boundary"); the 15 GPR pushes preserve that, so SysV's 16-byte
//!     alignment holds at the `call`.

use core::arch::{asm, global_asm};
use core::ptr::addr_of;

// ===========================================================================
// Trap entry asm: 256 per-vector thunks -> __alltraps -> x86_trap_handler.
// (a) PRE: a CPU exception/interrupt vectored to thunk N. For the 9 error-code
//     vectors the CPU already pushed a 32-bit error code; the rest push a
//     dummy 0. POST: a full TrapFrame (15 GPRs + vector + errcode + iret frame)
//     is on the stack, its address is in rdi, and x86_trap_handler is called;
//     on its return (Resume only) the frame is popped and `iretq` resumes.
// (b) ABI: extern "C"/SysV; RSP is 16-byte aligned at the `call` (CPU aligns
//     the iret frame to 16, +120 bytes of GPRs keeps it aligned). Intel syntax
//     (Rust default). Sources: Intel SDM Vol.3A §6 (esp. §6.13/§6.14, Table
//     6-1); OSDev "Interrupt Descriptor Table" / "Exceptions".
// (c) Tested by: kernel M1 sequence (int3 -> hook -> resume; "M1: traps OK").
// ===========================================================================
global_asm!(
    r#"
.section .text.trap, "ax", @progbits

// ---- 256 per-vector entry thunks ------------------------------------------
.macro TRAP_THUNK vec
__trap_thunk_\vec:
    .if (\vec == 8) || (\vec == 10) || (\vec == 11) || (\vec == 12) || (\vec == 13) || (\vec == 14) || (\vec == 17) || (\vec == 21) || (\vec == 30)
        // This vector carries a CPU-pushed 32-bit error code; do not add one.
    .else
        push 0          // dummy error code -> every TrapFrame is identical
    .endif
    push \vec           // vector number
    jmp  __alltraps
.endm

.altmacro
.set vecidx, 0
.rept 256
    TRAP_THUNK %vecidx
    .set vecidx, vecidx + 1
.endr
.noaltmacro

// ---- common entry: save GPRs, call Rust, restore, iretq -------------------
.global __alltraps
__alltraps:
    // Stack on entry (low->high): vector, errcode, rip, cs, rflags, rsp, ss.
    // Push the 15 GPRs so rax lands lowest -> matches `struct TrapFrame`.
    push r15
    push r14
    push r13
    push r12
    push r11
    push r10
    push r9
    push r8
    push rbp
    push rdi
    push rsi
    push rdx
    push rcx
    push rbx
    push rax

    mov  rdi, rsp           // arg0 = *mut TrapFrame
    call x86_trap_handler   // returns ONLY on TrapAction::Resume

    // Resume path: restore the GPRs, drop vector+errcode, return from interrupt.
    pop  rax
    pop  rbx
    pop  rcx
    pop  rdx
    pop  rsi
    pop  rdi
    pop  rbp
    pop  r8
    pop  r9
    pop  r10
    pop  r11
    pop  r12
    pop  r13
    pop  r14
    pop  r15
    add  rsp, 16            // discard the pushed vector + error code
    iretq

// ---- table of thunk addresses, consumed by idt::init ----------------------
.section .rodata, "a", @progbits
.balign 8
.global __trap_thunks
__trap_thunks:
.macro TRAP_ADDR vec
    .quad __trap_thunk_\vec
.endm
.altmacro
.set vecidx, 0
.rept 256
    TRAP_ADDR %vecidx
    .set vecidx, vecidx + 1
.endr
.noaltmacro
"#
);

/// 64-bit trap frame, in MEMORY order (lowest address first). The 15 GPRs are
/// pushed by `__alltraps` (rax lowest), then the thunk-pushed vector + error
/// code, then the CPU-pushed interrupt frame.
#[repr(C)]
#[allow(dead_code)] // most fields exist only to lay out the frame correctly
struct TrapFrame {
    rax: u64,
    rbx: u64,
    rcx: u64,
    rdx: u64,
    rsi: u64,
    rdi: u64,
    rbp: u64,
    r8: u64,
    r9: u64,
    r10: u64,
    r11: u64,
    r12: u64,
    r13: u64,
    r14: u64,
    r15: u64,
    vector: u64,
    error_code: u64,
    rip: u64,
    cs: u64,
    rflags: u64,
    rsp: u64,
    ss: u64,
}

/// Trap demux. The ONE place in `tb-hal/x86_64` that dereferences the raw
/// frame: it builds a safe [`crate::TrapInfo`], lets the registered safe hook
/// decide policy via [`crate::dispatch_trap`], then either returns (Resume —
/// `__alltraps` restores + `iretq`s) or parks the core (Halt — never returns).
#[no_mangle]
pub(super) extern "C" fn x86_trap_handler(frame: *mut TrapFrame) {
    // SAFETY: `__alltraps` passes rsp pointing at a fully-populated TrapFrame.
    let f = unsafe { &*frame };
    let vector = f.vector;
    let error_code = f.error_code & 0xFFFF_FFFF; // CPU error code is 32-bit

    let kind = match vector {
        3 => crate::TrapKind::Breakpoint, // #BP (int3)
        6 => crate::TrapKind::Undefined,  // #UD invalid opcode
        14 => crate::TrapKind::PageFault, // #PF
        _ => crate::TrapKind::Other,
    };
    let fault_addr = if vector == 14 {
        // SAFETY: reading CR2 is a side-effect-free MSR-like read; valid on #PF.
        unsafe { read_cr2() }
    } else {
        0
    };

    let info = crate::TrapInfo {
        kind,
        // cause = (vector number, 32-bit CPU error code), packed hi:lo.
        cause: (vector << 32) | error_code,
        fault_addr,
        pc: f.rip,
    };

    match crate::dispatch_trap(&info) {
        crate::TrapAction::Resume => {
            // #BP's saved RIP already points past int3 (see module header), so
            // `iretq` in __alltraps resumes the next instruction. Just return.
        }
        crate::TrapAction::Halt => super::halt(),
    }
}

/// Read CR2 (the linear address of the last page-fault). Intel SDM Vol.3A
/// §2.5 / §6.15 (#PF).
#[inline]
unsafe fn read_cr2() -> u64 {
    let cr2: u64;
    asm!("mov {}, cr2", out(reg) cr2, options(nomem, nostack, preserves_flags));
    cr2
}

/// Entry address of the per-vector thunk for `vector` (0..256), read from the
/// `__trap_thunks` table emitted by the `global_asm!` above. Used by
/// `idt::init` to populate the gate descriptors.
pub(super) fn thunk(vector: usize) -> u64 {
    extern "C" {
        static __trap_thunks: [usize; 256];
    }
    // SAFETY: __trap_thunks is the 256-entry `.quad` table below; idt::init
    // only ever passes `vector` in 0..256, so the index is in bounds.
    unsafe { *(addr_of!(__trap_thunks) as *const usize).add(vector) as u64 }
}

/// Raise a breakpoint exception (`int3`, #BP, vector 3) from safe code.
///
/// Proves the take-trap -> Rust-dispatch -> resume path: the registered hook
/// prints and returns `TrapAction::Resume`, and because the CPU-saved RIP
/// already points past `int3`, execution continues at the next instruction.
/// Requires `super::install_traps()` to have run first.
pub fn breakpoint() {
    // (a) PRE: traps installed. POST: #BP taken, dispatched, (M1 policy) resumed.
    // (b) ABI: `int3` (0xCC). The handler runs on the current stack and may
    //     touch memory/serial, so NO nomem/nostack; flags survive via `iretq`.
    // (c) Tested by: kernel M1 sequence ("trap: breakpoint, resuming").
    unsafe { asm!("int3") }
}

//! x86_64 architecture backend for `tb-hal`.
//!
//! Exposes the safe primitives that `tb-hal`'s public API
//! (`serial_init`, `serial_write_byte`, `serial_write_str`, `halt`,
//! `install_traps`, `breakpoint`) delegates to via `arch::mod`. ALL x86_64
//! `unsafe` and assembly is confined to this `arch::x86_64` subtree
//! (KERNEL-FOUNDATION-SPEC §1); every other crate is `#![forbid(unsafe_code)]`.
//!
//! M0 boot path is PVH: `boot` emits the `XEN_ELFNOTE_PHYS32_ENTRY` note and
//! the (bootstrap-only) 32->64 trampoline; `serial` is the 16550 COM1 driver.
//! M1 adds CPU trap handling: `gdt` installs a permanent flat 64-bit GDT + TSS
//! (IST stacks), `idt` installs the 256-gate IDT, and `trap` holds the entry
//! thunks + the extern "C" handler that dispatches into safe Rust policy.

// `_start`, the PVH note and the 32->64 trampoline live here. The module is
// pulled into the final link because the linker script's `ENTRY(_start)`
// turns `_start` into a needed symbol, forcing extraction from the rlib.
pub mod boot;
pub mod serial;

// M1 trap stack: GDT/TSS, IDT, and the trap entry/dispatch asm + handler.
pub mod gdt;
pub mod idt;
pub mod trap;

pub use serial::{serial_init, serial_write_byte};

// `breakpoint()` is re-exported as part of tb-hal's public trap surface; the
// `int3` lives in `trap.rs`. `set_trap_hook`/`TrapInfo`/`TrapKind`/`TrapAction`
// and the `dispatch_trap` glue live at the crate root (`lib.rs`).
pub use trap::breakpoint;

use core::sync::atomic::{AtomicBool, Ordering};

/// Guards `install_traps()` so the permanent GDT/TSS/IDT are only built once
/// per vCPU even if it is called more than once.
static TRAPS_INSTALLED: AtomicBool = AtomicBool::new(false);

/// Install real CPU exception/interrupt handling: load the permanent GDT+TSS
/// (with IST stacks) FIRST, then the IDT (whose #DF/NMI/#MC gates reference
/// those IST stacks). Idempotent; called once from `rust_main` via
/// `tb_hal::install_traps()`.
pub fn install_traps() {
    if TRAPS_INSTALLED.swap(true, Ordering::SeqCst) {
        return;
    }
    // Order matters: the IDT's IST indices select TSS stacks the GDT installs.
    gdt::init();
    idt::init();
}

/// Halt the calling (single) vCPU forever.
///
/// Masks interrupts and parks the core in a `hlt` loop. Used as the M0
/// Definition-of-Done terminator after the marker is printed, as the fatal
/// (`TrapAction::Halt`) trap terminator, and as the `#[panic_handler]`
/// fallback in the kernel crate. Never returns.
#[inline]
pub fn halt() -> ! {
    loop {
        // (a) PRE: any CPU state. POST: interrupts masked, core parked; the
        //     function never observably returns (the surrounding loop re-arms
        //     `hlt` after any spurious NMI/SMI wake).
        // (b) ABI: no operands; clobbers nothing; nomem/nostack. `hlt` clears
        //     no caller state; `cli` only affects IF.
        // (c) Tested by: scripts/run-x86_64.sh (kernel halts after emitting
        //     its markers; the runner times out and scrapes COM1).
        unsafe {
            core::arch::asm!("cli", "hlt", options(nomem, nostack, preserves_flags));
        }
    }
}

//! aarch64 EL1 exception vector table (`VBAR_EL1`) and the trap entry/exit path.
//!
//! This is unit **A4 / milestone M1** on aarch64. Like `boot.rs` it is compiled
//! purely for its `global_asm!` side effects: nothing here is referenced from
//! Rust except by symbol -- the table label `__exception_vectors` (loaded into
//! `VBAR_EL1` by `boot.rs::_start` and re-armed by `mod.rs::install_traps`) and
//! the extern `aarch64_trap_handler` (defined in `trap.rs`). The linker keeps
//! the whole table via `KEEP(*(.text._vectors))` in `kernel/linker/aarch64.ld`.
//!
//! Layout (verified facts -- obey exactly):
//!  * `VBAR_EL1` points at a **2 KiB-aligned** table of **16 entries x 128 B**.
//!    The 16 slots are, in order, the cross product
//!    {Current-EL-SP0, Current-EL-SPx, Lower-EL-AArch64, Lower-EL-AArch32}
//!    x {Synchronous, IRQ/vIRQ, FIQ/vFIQ, SError/vSError}.
//!      - Arm Architecture Reference Manual (DDI 0487), D1 "AArch64 Exception
//!        model" / "Exception vectors" (the VBAR_ELx + 16x0x80 table).
//!      - OSDev Wiki, "Exception handling in AArch64" (vector table base must be
//!        2 KiB aligned; each of the 16 entries is 0x80 bytes).
//!      - Cross-checked against Linux `arch/arm64/kernel/entry.S`:
//!        `SYM_CODE_START(vectors)` is `.align 11` (2^11 = 2 KiB) and each
//!        `kernel_ventry` is `.align 7` (2^7 = 128 B); the ventry order is
//!        EL1t{sync,irq,fiq,err}, EL1h{sync,irq,fiq,err}, EL0_64{...}, EL0_32{...}.
//!  * The kernel boots and runs at **EL1h** (handler, `SP_EL1` == "SPx"), so a
//!    synchronous exception from our own code -- e.g. `brk #0` -- is taken
//!    through the **"Current EL with SPx, Synchronous"** slot: index 4, byte
//!    offset **0x200**. For M1 that is the only slot with a real handler; every
//!    other slot routes to a common stub (`__vec_other`) that reports the trap
//!    as `TrapKind::Other` (the default policy then halts).
//!  * Save / restore mirrors Linux `entry.S` `kernel_entry` / `kernel_exit`:
//!    push x0..x30 + `ELR_EL1` + `SPSR_EL1`; `mov x0, sp`; `bl` into Rust;
//!    reload `ELR_EL1`/`SPSR_EL1` (the handler may have advanced `ELR_EL1` by 4
//!    to resume past a `brk`); pop x0..x30; `eret`.
//!  * The target spec `targets/aarch64-tabos-none.json` is `abi: softfloat`
//!    with `-fp-armv8,-neon`, so the V/SIMD registers carry no live state and
//!    are intentionally NOT part of the frame (FP context save lands with
//!    preemption / userspace, not M1).

use core::arch::global_asm;

// -- __exception_vectors + trap entry/exit ----------------------------------
// (a) PRE : VBAR_EL1 == &__exception_vectors (2 KiB aligned); a synchronous
//           exception is taken at Current-EL-SPx. POST: a TrapFrame of x0..x30
//           + ELR_EL1 + SPSR_EL1 is built on the exception stack, Rust dispatch
//           runs, then state (possibly with ELR_EL1 advanced past `brk`) is
//           restored and `eret` resumes the interrupted context.
// (b) ABI  : SP must be 16-aligned on entry (kernel maintains it); the 0x110
//           frame keeps it aligned across `bl aarch64_trap_handler` (AAPCS64
//           arg0 = x0 = &TrapFrame, arg1 = x1 = source tag). `bl` clobbers x30,
//           which was already saved. `eret` restores PSTATE from SPSR_EL1.
// (c) TEST : scripts/run-aarch64.sh -- breakpoint() takes slot 0x200, the hook
//           resumes, and the kernel prints "M1: traps OK".
global_asm!(
    r#"
    // ---- context save: x0..x30, ELR_EL1, SPSR_EL1 -> 0x110-byte TrapFrame ----
    .macro SAVE_CONTEXT
    sub  sp, sp, #0x110
    stp  x0,  x1,  [sp, #0x00]
    stp  x2,  x3,  [sp, #0x10]
    stp  x4,  x5,  [sp, #0x20]
    stp  x6,  x7,  [sp, #0x30]
    stp  x8,  x9,  [sp, #0x40]
    stp  x10, x11, [sp, #0x50]
    stp  x12, x13, [sp, #0x60]
    stp  x14, x15, [sp, #0x70]
    stp  x16, x17, [sp, #0x80]
    stp  x18, x19, [sp, #0x90]
    stp  x20, x21, [sp, #0xA0]
    stp  x22, x23, [sp, #0xB0]
    stp  x24, x25, [sp, #0xC0]
    stp  x26, x27, [sp, #0xD0]
    stp  x28, x29, [sp, #0xE0]
    str  x30,      [sp, #0xF0]
    mrs  x9,  elr_el1            // x9/x10 already saved above; free to reuse
    mrs  x10, spsr_el1
    stp  x9,  x10, [sp, #0xF8]   // elr @ 0xF8, spsr @ 0x100
    .endm

    // ---- context restore (elr/spsr first, then GPRs reclaim x9/x10) ----------
    .macro RESTORE_CONTEXT
    ldp  x9,  x10, [sp, #0xF8]   // handler may have written elr (brk resume)
    msr  elr_el1,  x9
    msr  spsr_el1, x10
    ldp  x0,  x1,  [sp, #0x00]
    ldp  x2,  x3,  [sp, #0x10]
    ldp  x4,  x5,  [sp, #0x20]
    ldp  x6,  x7,  [sp, #0x30]
    ldp  x8,  x9,  [sp, #0x40]   // restores the real x9
    ldp  x10, x11, [sp, #0x50]   // restores the real x10
    ldp  x12, x13, [sp, #0x60]
    ldp  x14, x15, [sp, #0x70]
    ldp  x16, x17, [sp, #0x80]
    ldp  x18, x19, [sp, #0x90]
    ldp  x20, x21, [sp, #0xA0]
    ldp  x22, x23, [sp, #0xB0]
    ldp  x24, x25, [sp, #0xC0]
    ldp  x26, x27, [sp, #0xD0]
    ldp  x28, x29, [sp, #0xE0]
    ldr  x30,      [sp, #0xF0]
    add  sp, sp, #0x110
    .endm

    // ---- one 128-byte vector slot: align, then branch to a trampoline --------
    .macro VEC_SLOT target
    .balign 0x80
    b   \target
    .endm

    .section .text._vectors, "ax"
    .balign 0x800                 // VBAR_EL1 requires 2 KiB alignment
    .globl __exception_vectors
__exception_vectors:
    // --- Current EL with SP0 (EL1t) -- we never run on SP0; treat as fatal ---
    VEC_SLOT __vec_other          // 0x000 Synchronous
    VEC_SLOT __vec_other          // 0x080 IRQ / vIRQ
    VEC_SLOT __vec_other          // 0x100 FIQ / vFIQ
    VEC_SLOT __vec_other          // 0x180 SError / vSError
    // --- Current EL with SPx (EL1h) -- this is where our kernel runs ---------
    VEC_SLOT __vec_sync           // 0x200 Synchronous  <-- real handler (M1)
    VEC_SLOT __vec_other          // 0x280 IRQ / vIRQ   (masked in M1)
    VEC_SLOT __vec_other          // 0x300 FIQ / vFIQ   (masked in M1)
    VEC_SLOT __vec_other          // 0x380 SError / vSError
    // --- Lower EL using AArch64 -- no userspace in M1; fatal -----------------
    VEC_SLOT __vec_other          // 0x400 Synchronous
    VEC_SLOT __vec_other          // 0x480 IRQ
    VEC_SLOT __vec_other          // 0x500 FIQ
    VEC_SLOT __vec_other          // 0x580 SError
    // --- Lower EL using AArch32 -- no AArch32 in M1; fatal -------------------
    VEC_SLOT __vec_other          // 0x600 Synchronous
    VEC_SLOT __vec_other          // 0x680 IRQ
    VEC_SLOT __vec_other          // 0x700 FIQ
    VEC_SLOT __vec_other          // 0x780 SError
    .balign 0x80                  // pad slot 15 to a full 128 B: table == 0x800

    // ---- trampolines (live just past the 2 KiB table, still KEEP'd) ----------
__vec_sync:                       // Current-EL-SPx synchronous: brk/undef/abort
    SAVE_CONTEXT
    mov  x1, #0                   // source = 0: synchronous, current EL (SPx)
    b    __trap_dispatch
__vec_other:                      // every other vector: unexpected -> fatal
    SAVE_CONTEXT
    mov  x1, #1                   // source = 1: unexpected vector
    b    __trap_dispatch
__trap_dispatch:
    mov  x0, sp                   // AAPCS64 arg0 = &TrapFrame
    bl   aarch64_trap_handler     // extern "C" in trap.rs; may halt (Halt path)
    RESTORE_CONTEXT               // Resume path: pop state (elr maybe +4)
    eret
"#
);

//! aarch64 trap dispatch: the one place that derefs the raw exception frame.
//!
//! `vectors.rs` marshals a `TrapFrame` on the exception stack and `bl`s into
//! [`aarch64_trap_handler`] here. This module reads the cause from `ESR_EL1`
//! (and the faulting VA from `FAR_EL1`), builds a *safe* [`crate::TrapInfo`],
//! and hands it to the crate-level policy hook via [`crate::dispatch_trap`].
//! Per the framekernel rule, POLICY lives in safe Rust (the kernel crate's
//! `set_trap_hook`); this file only does the unavoidable raw-frame plumbing.
//!
//! Contract with `lib.rs` (the crate facade, owned separately). M1 expects:
//! ```ignore
//! pub struct TrapInfo { pub kind: TrapKind, pub cause: u64,
//!                       pub fault_addr: u64, pub pc: u64 }
//! pub enum TrapKind  { Breakpoint, PageFault, Undefined, Other }  // Clone+Copy
//! pub enum TrapAction { Resume, Halt }
//! pub fn set_trap_hook(f: fn(&TrapInfo) -> TrapAction);  // default hook = Halt
//! pub(crate) fn dispatch_trap(info: &TrapInfo) -> TrapAction; // loads the hook
//! ```
//! Both arch back-ends call `crate::dispatch_trap`; `aarch64::mod::install_traps`
//! arms `VBAR_EL1` and [`breakpoint`] raises the test `brk #0`.
//!
//! Verified facts (obey exactly):
//!  * `ESR_EL1.EC` is bits[31:26] (6 bits). Arm ARM (DDI 0487) D17.2.37
//!    "ESR_EL1, Exception Syndrome Register (EL1)". Cross-checked vs Linux
//!    `arch/arm64/include/asm/esr.h`: `ESR_ELx_EC_SHIFT == 26`.
//!  * EC values (Linux `esr.h`, Arm ARM D17.2.37 "EC encodings"):
//!      - `0x3C` `ESR_ELx_EC_BRK64`   : BRK instruction in AArch64 state.
//!      - `0x00` `ESR_ELx_EC_UNKNOWN` : "Unknown reason" (covers UDF/undefined).
//!      - `0x24` `ESR_ELx_EC_DABT_LOW`: Data Abort from a lower EL.
//!      - `0x25` `ESR_ELx_EC_DABT_CUR`: Data Abort without a change in EL.
//!  * `FAR_EL1` holds the faulting virtual address for data/instruction aborts
//!    (Arm ARM D17.2.40 "FAR_EL1").
//!  * `brk #0` is a SYNCHRONOUS exception: `ELR_EL1` points AT the `brk`
//!    instruction (Arm ARM D1: the preferred return address of a synchronous
//!    exception is the faulting instruction). To resume you MUST advance
//!    `ELR_EL1` by 4 before `eret`. This is the opposite of x86 `#BP` (int3),
//!    a *trap* whose saved RIP already points to the following instruction
//!    (Intel SDM Vol.3 SS6.15, interrupt 3), so x86 needs no RIP adjustment.

use crate::{TrapAction, TrapInfo, TrapKind};

/// Saved CPU context for one aarch64 exception, built on the exception stack by
/// `SAVE_CONTEXT` in `vectors.rs`. `#[repr(C)]`; the byte offsets are part of
/// the ABI shared with that assembly (`gpr[i]` at `i*8`, `elr` at 0xF8,
/// `spsr` at 0x100). `_pad` keeps the frame a multiple of 16 so SP stays
/// 16-byte aligned across the handler call.
#[repr(C)]
struct TrapFrame {
    /// x0..x30 (x30 = LR), offsets 0x00..0xF0.
    gpr: [u64; 31],
    /// ELR_EL1 at exception entry (the preferred return address), offset 0xF8.
    /// Writing this and returning makes `eret` resume there (brk: advance +4).
    elr: u64,
    /// SPSR_EL1 at exception entry (saved PSTATE), offset 0x100.
    spsr: u64,
    /// Alignment pad; frame size is 0x110 (16-aligned).
    _pad: u64,
}

// Compile-time lock on the layout the assembly in `vectors.rs` assumes.
const _: () = assert!(core::mem::size_of::<TrapFrame>() == 0x110);
const _: () = assert!(core::mem::offset_of!(TrapFrame, elr) == 0xF8);
const _: () = assert!(core::mem::offset_of!(TrapFrame, spsr) == 0x100);

// ESR_EL1 exception-class field and the EC codes we classify (see file note).
const ESR_EC_SHIFT: u64 = 26;
const ESR_EC_MASK: u64 = 0x3F;
const EC_UNKNOWN: u64 = 0x00; // undefined / UDF
const EC_DABT_LOWER: u64 = 0x24; // data abort, lower EL
const EC_DABT_CURRENT: u64 = 0x25; // data abort, current EL
const EC_BRK64: u64 = 0x3C; // BRK from AArch64

// Source tag passed in x1 by the `vectors.rs` trampolines.
const SOURCE_SYNC_CURRENT_SPX: u64 = 0; // real handler (synchronous, our EL)

#[inline(always)]
fn read_esr_el1() -> u64 {
    let v: u64;
    // SAFETY: ESR_EL1 is an EL1-readable system register; `mrs` has no memory
    // or stack effect and leaves NZCV unchanged. We run at EL1.
    unsafe {
        core::arch::asm!("mrs {0}, esr_el1", out(reg) v,
            options(nomem, nostack, preserves_flags));
    }
    v
}

#[inline(always)]
fn read_far_el1() -> u64 {
    let v: u64;
    // SAFETY: as `read_esr_el1`; FAR_EL1 is an EL1-readable system register.
    unsafe {
        core::arch::asm!("mrs {0}, far_el1", out(reg) v,
            options(nomem, nostack, preserves_flags));
    }
    v
}

/// Trap handler invoked from `vectors.rs` (`bl aarch64_trap_handler`).
///
/// `frame` is `sp` immediately after `SAVE_CONTEXT`; `source` is 0 for the
/// Current-EL-SPx synchronous slot and 1 for every other (unexpected) vector.
/// Reads the cause, builds a safe [`crate::TrapInfo`], and runs the registered
/// policy hook. On [`TrapAction::Resume`] of a `brk` it advances the saved
/// `ELR_EL1` by 4 (one A64 instruction) so `eret` lands past the `brk`; on
/// [`TrapAction::Halt`] it parks the core via [`crate::halt`] and never returns.
#[no_mangle]
pub extern "C" fn aarch64_trap_handler(frame: *mut TrapFrame, source: u64) {
    // SAFETY: `frame` is the SP that the vector trampoline produced after its
    // 0x110-byte `SAVE_CONTEXT` push -- a fully-initialised, 16-aligned
    // `TrapFrame` that stays live for this whole call. Single core, with
    // interrupts masked while we run, so we are the only accessor.
    let frame = unsafe { &mut *frame };

    let esr = read_esr_el1();
    let far = read_far_el1();
    let ec = (esr >> ESR_EC_SHIFT) & ESR_EC_MASK;

    // Classify. Only the synchronous current-EL slot has a meaningful ESR EC;
    // any other vector is an unexpected fault -> Other (default policy halts).
    let (kind, is_breakpoint) = if source != SOURCE_SYNC_CURRENT_SPX {
        (TrapKind::Other, false)
    } else {
        match ec {
            EC_BRK64 => (TrapKind::Breakpoint, true),
            EC_UNKNOWN => (TrapKind::Undefined, false),
            EC_DABT_LOWER | EC_DABT_CURRENT => (TrapKind::PageFault, false),
            _ => (TrapKind::Other, false),
        }
    };

    let info = TrapInfo {
        kind,
        cause: esr,
        fault_addr: far,
        pc: frame.elr,
    };

    match crate::dispatch_trap(&info) {
        TrapAction::Resume => {
            // brk: ELR points AT the instruction; step over its 4 bytes so the
            // `eret` in `vectors.rs` resumes at the following instruction.
            if is_breakpoint {
                frame.elr = frame.elr.wrapping_add(4);
            }
        }
        // Fatal: the hook already reported it; park the core (never returns, so
        // the trampoline's restore/eret is intentionally not reached).
        TrapAction::Halt => crate::halt(),
    }
}

/// Raise a software breakpoint (`brk #0`) -- the safe M1 trap-test trigger.
///
/// With traps installed this is taken through the Current-EL-SPx synchronous
/// vector (`ESR_EL1.EC == 0x3C`), classified as [`TrapKind::Breakpoint`], and,
/// when the hook returns [`TrapAction::Resume`], resumed at the next
/// instruction (the handler advances `ELR_EL1` by 4). The `unsafe` is confined
/// here so the caller (the `#![forbid(unsafe_code)]` kernel) stays safe.
pub fn breakpoint() {
    // SAFETY: `brk #0` raises a synchronous Breakpoint exception and has no
    // memory, stack, or flag effects of its own; the handler save/restores
    // (incl. SPSR/NZCV) so the caller's state is preserved across the trap.
    unsafe {
        core::arch::asm!("brk #0", options(nomem, nostack, preserves_flags));
    }
}

//! aarch64 backend for the `tb-hal` foundation crate.
//!
//! One of the two `#[cfg(target_arch)]` arms re-exported by `arch/mod.rs`. It
//! exposes the aarch64 primitives the safe `tb-hal` public API (`lib.rs`)
//! delegates to: [`serial_init`], [`serial_write_byte`], [`halt`] (M0) plus the
//! M1 trap surface [`install_traps`] and [`breakpoint`]. (`serial_write_str` is
//! composed in `lib.rs` from `serial_write_byte`, so it is arch-independent.)
//!
//! Boot contract for the M0/M1 QEMU `virt` path (verified facts,
//! KERNEL-FOUNDATION-SPEC SS2): the vCPU enters `_start` at **EL1h, MMU OFF,
//! DAIF masked**, with **x0 = FDT/DTB pointer** (AAPCS64 arg0 already).
//! `boot.rs` owns that entry; `serial.rs` owns the PL011 UART; `vectors.rs`
//! owns the `VBAR_EL1` table; `trap.rs` owns the Rust trap dispatch.

mod boot; // _start; arms VBAR_EL1; pure side-effect (`global_asm!`) module.
mod serial; // PL011 @ 0x0900_0000 (QEMU `virt` UART0).
mod trap; // Rust trap dispatch + breakpoint(); the only raw-frame deref.
mod vectors; // VBAR_EL1 table + entry/exit stubs; pure `global_asm!` module.

pub use serial::{serial_init, serial_write_byte};
pub use trap::breakpoint;

// -- install_traps() --------------------------------------------------------
// (a) PRE : called once from rust_main, after serial_init, at EL1h. POST:
//           VBAR_EL1 == &__exception_vectors (the 2 KiB-aligned table in
//           vectors.rs) and an `isb` has made the new vector base
//           architecturally visible. Idempotent: `_start` already pre-armed the
//           very same table, so a second call just re-writes the same value.
// (b) ABI : clobbers one scratch x-register; touches no memory/stack; takes no
//           args. Arm ARM D19.2 requires a context-synchronisation event after
//           writing VBAR_EL1 before relying on it -- the `isb` provides it.
// (c) TEST: scripts/run-aarch64.sh -- after install, breakpoint() is caught,
//           the hook resumes, and the kernel prints "M1: traps OK".
/// Install the EL1 exception vectors (`VBAR_EL1`). Idempotent; call once.
pub fn install_traps() {
    // SAFETY: writing VBAR_EL1 is legal at EL1 and merely (re)selects our own
    // 2 KiB-aligned vector table (`vectors.rs`); `adrp/add :lo12:` form its
    // address with no memory access, and `isb` synchronises the change.
    unsafe {
        core::arch::asm!(
            "adrp {t}, __exception_vectors",
            "add  {t}, {t}, :lo12:__exception_vectors",
            "msr  vbar_el1, {t}",
            "isb",
            t = out(reg) _,
            options(nomem, nostack, preserves_flags),
        );
    }
}

// -- halt() -----------------------------------------------------------------
// (a) PRE : any state; called on the M0/M1 happy path after the marker is
//           flushed, from the kernel #[panic_handler], and from the trap
//           handler's fatal (Halt) path. POST: never returns -- the vCPU is
//           parked in a low-power wait, re-parking on any wake event.
// (b) ABI : `wfi` clobbers nothing, touches no memory/stack, preserves NZCV.
// (c) TEST: scripts/run-aarch64.sh -- the kernel reaches here after printing
//           "M1: traps OK"; the runner times out and asserts the marker.
/// Halt the current vCPU forever (low-power wait loop).
pub fn halt() -> ! {
    loop {
        // SAFETY: `wfi` is an unprivileged hint with no memory or stack
        // effects; it is always legal at EL1 and merely suspends the core
        // until a wake event, after which we loop and re-park.
        unsafe {
            core::arch::asm!("wfi", options(nomem, nostack, preserves_flags));
        }
    }
}

//! aarch64 boot entry (`_start`): stack, `.bss`, and the initial `VBAR_EL1` arm.
//!
//! All assembly in TABOS is confined to `tb-hal`; this module is the aarch64
//! half of unit **A1/A2** in KERNEL-FOUNDATION-SPEC SS3. It is compiled purely
//! for its `global_asm!` side effects -- nothing here is referenced from Rust;
//! the linker keeps `_start` via `ENTRY(_start)` + `KEEP()` in
//! `kernel/linker/aarch64.ld`.
//!
//! The exception vector table itself moved to `vectors.rs` at M1 (unit A4):
//! `_start` only *pre-arms* `VBAR_EL1` with the `__exception_vectors` symbol so
//! a fault during early boot is still vectored (the default policy halts).
//! `mod.rs::install_traps()` re-arms the same table from `rust_main` once the
//! console is up; the two writes are identical and idempotent.
//!
//! Boot contract (QEMU `virt`, `-kernel <ELF>`; verified -- Firecracker sets
//! the parity state PSTATE = 0x3c5 = EL1h with D/A/I/F masked): the vCPU enters
//! at **EL1h, MMU OFF, DAIF masked, x0 = FDT pointer**. QEMU loads the PT_LOAD
//! segments at their p_paddr and jumps to e_entry (`_start`).

use core::arch::global_asm;

// -- _start -----------------------------------------------------------------
// (a) PRE : EL1h, MMU OFF, DAIF masked, x0 = FDT/DTB pointer (QEMU `virt` boot
//           ABI). POST: SP = top of the 16 KiB boot stack, .bss zeroed,
//           VBAR_EL1 = __exception_vectors (vectors.rs), control tail-branched
//           to rust_main(x0) with x0 (FDT) preserved as AAPCS64 arg0.
// (b) ABI : clobbers x1, x2 only; x0 preserved end-to-end; no stack used before
//           SP is set; `b` (not `bl`) -- rust_main is `-> !`, never returns.
// (c) TEST: scripts/run-aarch64.sh asserts the milestone marker on serial.
global_asm!(
    r#"
    .section .text._start, "ax"
    .globl _start
_start:
    // x0 holds the FDT pointer on entry; it is never touched below, so it
    // survives untouched into rust_main as AAPCS64 argument 0.

    // (1) Establish the boot stack (linker guarantees 16-byte alignment).
    adrp x1, __boot_stack_top
    add  x1, x1, :lo12:__boot_stack_top
    mov  sp, x1

    // (2) Zero .bss [__bss_start, __bss_end) eight bytes at a time. Both bounds
    //     are 16-byte aligned, so the doubleword stores never overrun.
    adrp x1, __bss_start
    add  x1, x1, :lo12:__bss_start
    adrp x2, __bss_end
    add  x2, x2, :lo12:__bss_end
0:  cmp  x1, x2
    b.hs 1f
    str  xzr, [x1], #8
    b    0b
1:

    // (3) Pre-arm VBAR_EL1 with the M1 exception vector table (vectors.rs) and
    //     synchronize, so any early fault is vectored before we enter Rust.
    //     install_traps() re-arms this same table once the console is up.
    adrp x1, __exception_vectors
    add  x1, x1, :lo12:__exception_vectors
    msr  vbar_el1, x1
    isb

    // (4) Enter safe Rust. x0 still = FDT pointer.
    b    rust_main
"#
);

//! `tb-hal` — TABOS Hardware Abstraction Layer (M0 surface + M1 traps).
//!
//! This crate is the single place where `unsafe` and assembly are allowed in
//! TABOS (framekernel rule, KERNEL-FOUNDATION-SPEC.md §1). The raw pokes live in
//! the per-arch submodules under `arch/`; THIS file is a thin, mostly-safe
//! facade exposing the symbols the `kernel` crate is allowed to call:
//!
//! M0 serial + park:
//!   * [`serial_init`], [`serial_write_byte`], [`serial_write_str`], [`halt`]
//!
//! M1 traps (this milestone):
//!   * [`install_traps`]  — load the permanent GDT+TSS+IDT (x86_64) / set
//!     `VBAR_EL1` (aarch64). Idempotent, called once from `rust_main`.
//!   * [`breakpoint`]     — execute a software breakpoint (`int3` / `brk #0`).
//!   * [`set_trap_hook`]  — register the safe dispatch policy hook.
//!   * [`TrapInfo`] / [`TrapKind`] / [`TrapAction`] — the safe trap-dispatch ABI.
//!
//! POLICY lives in safe Rust: tb-hal's per-arch assembly marshals a raw
//! `TrapFrame`, an `extern "C"` handler in tb-hal (the ONLY place that derefs
//! the raw frame, `unsafe`) builds a safe [`TrapInfo`] and calls the registered
//! hook via [`dispatch_trap`]. The default hook returns [`TrapAction::Halt`].

#![no_std]
#![deny(missing_docs)]

use core::sync::atomic::{AtomicUsize, Ordering};

mod arch;

/// Initialise the early serial console for the current architecture.
///
/// * x86_64: legacy 16550 UART, COM1 @ I/O port `0x3F8`.
/// * aarch64: PL011 UART0 @ MMIO `0x0900_0000` (QEMU `virt` first-light).
///
/// Must be called once before any [`serial_write_byte`] / [`serial_write_str`].
pub fn serial_init() {
    arch::serial_init();
}

/// Write a single byte to the early serial console, blocking until the UART can
/// accept it.
pub fn serial_write_byte(b: u8) {
    arch::serial_write_byte(b);
}

/// Write a string to the early serial console, byte by byte (blocking).
///
/// Pure safe Rust: this is just a loop over [`serial_write_byte`]; it performs
/// no `unsafe` itself.
pub fn serial_write_str(s: &str) {
    for &b in s.as_bytes() {
        arch::serial_write_byte(b);
    }
}

/// Halt the (single) vCPU forever. Never returns.
///
/// * x86_64: masked `cli; hlt` spin.
/// * aarch64: `wfi` spin with interrupts masked.
pub fn halt() -> ! {
    arch::halt()
}

// ===========================================================================
// M1: trap installation + safe dispatch ABI
// ===========================================================================

/// Install real CPU exception/interrupt handling for the current architecture.
///
/// * x86_64: build and load a PERMANENT flat 64-bit GDT (null, ring0 code,
///   ring0 data, 64-bit TSS), reload `CS`/data segments, `ltr` the TSS, then
///   load a 256-entry IDT of 64-bit interrupt gates. `#DF`/NMI/`#MC` are routed
///   through TSS IST stacks.
/// * aarch64: point `VBAR_EL1` at the 2 KiB-aligned, 16×128-byte vector table.
///
/// Idempotent: safe to call more than once (each call rebuilds the descriptor
/// tables from scratch). Call once early from `rust_main`, before [`breakpoint`].
pub fn install_traps() {
    arch::install_traps();
}

/// Execute a software breakpoint trap on the current architecture.
///
/// * x86_64: `int3` (`#BP`, vector 3) — a TRAP whose CPU-saved `RIP` already
///   points PAST the instruction, so it resumes automatically on
///   [`TrapAction::Resume`].
/// * aarch64: `brk #0` — a SYNCHRONOUS exception (`ESR_EL1.EC = 0x3C`) whose
///   `ELR_EL1` points AT the instruction; the trap entry advances `ELR_EL1` by
///   4 on [`TrapAction::Resume`].
pub fn breakpoint() {
    arch::breakpoint();
}

/// The architecture-neutral classification of a trap, derived in the per-arch
/// `extern "C"` handler from the raw cause (vector + error code on x86_64,
/// `ESR_EL1.EC` on aarch64).
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum TrapKind {
    /// Software breakpoint: x86 `#BP` (vector 3) / aarch64 `brk` (EC `0x3C`).
    Breakpoint,
    /// Page / data fault: x86 `#PF` (vector 14) / aarch64 data abort
    /// (EC `0x24`/`0x25`). [`TrapInfo::fault_addr`] holds the faulting address.
    PageFault,
    /// Undefined / invalid instruction: x86 `#UD` (vector 6) / aarch64 Unknown
    /// (EC `0x00`).
    Undefined,
    /// Any other trap not specially classified above.
    Other,
}

/// What the dispatch hook asks tb-hal to do after a trap is handled.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum TrapAction {
    /// Return from the trap entry so execution continues past the trapping
    /// instruction (x86: `iretq`; aarch64: `eret`, advancing `ELR_EL1` by 4 for
    /// the at-instruction synchronous breakpoint).
    Resume,
    /// Do not return; park the vCPU forever. Used for fatal faults and as the
    /// default policy when no hook is registered.
    Halt,
}

/// A safe, fully-owned description of a trap, handed to the dispatch hook.
///
/// Built inside tb-hal's per-arch handler from the raw `TrapFrame`; it borrows
/// nothing from the raw frame, so the hook (in the otherwise-`forbid(unsafe)`
/// kernel crate) can read it freely.
#[derive(Clone, Copy, Debug)]
pub struct TrapInfo {
    /// The architecture-neutral kind of this trap.
    pub kind: TrapKind,
    /// Raw cause word. x86_64: `(vector << 32) | (error_code & 0xFFFF_FFFF)`.
    /// aarch64: the full `ESR_EL1` value (EC = bits `[31:26]`).
    pub cause: u64,
    /// Faulting address for memory faults (x86 `CR2` for `#PF`; aarch64
    /// `FAR_EL1` for a data abort), otherwise `0`.
    pub fault_addr: u64,
    /// The trapping instruction pointer (x86 saved `RIP`; aarch64 `ELR_EL1`).
    pub pc: u64,
}

/// Storage for the registered trap hook: a `fn(&TrapInfo) -> TrapAction`
/// reinterpreted as `usize`. `0` means "no hook registered → use the default
/// halt policy". `AtomicUsize` because tb-hal is `no_std` with no locks; the
/// pointer is written once at boot and read on every trap.
static TRAP_HOOK: AtomicUsize = AtomicUsize::new(0);

/// The default policy when no hook has been registered: always halt.
fn default_trap_hook(_info: &TrapInfo) -> TrapAction {
    TrapAction::Halt
}

/// Register the safe trap-dispatch policy hook.
///
/// The hook is a plain function pointer `fn(&TrapInfo) -> TrapAction`; it lives
/// in safe Rust (e.g. the kernel crate under `#![forbid(unsafe_code)]`) and
/// decides per-trap whether to [`TrapAction::Resume`] or [`TrapAction::Halt`].
pub fn set_trap_hook(hook: fn(&TrapInfo) -> TrapAction) {
    TRAP_HOOK.store(hook as usize, Ordering::Release);
}

/// Dispatch a trap to the registered hook (or the default halt policy).
///
/// Called by each per-arch `extern "C"` handler with a [`TrapInfo`] it built
/// from the raw frame. This is the safe boundary between the raw-frame deref
/// (per-arch, `unsafe`) and the policy hook (safe).
pub(crate) fn dispatch_trap(info: &TrapInfo) -> TrapAction {
    let raw = TRAP_HOOK.load(Ordering::Acquire);
    if raw == 0 {
        return default_trap_hook(info);
    }
    // SAFETY: `raw` is non-zero here, so it was produced by `set_trap_hook`
    // from a valid `fn(&TrapInfo) -> TrapAction` via `hook as usize`. A function
    // pointer and `usize` are both pointer-sized; this transmute is the exact
    // inverse of that cast.
    let hook: fn(&TrapInfo) -> TrapAction =
        unsafe { core::mem::transmute::<usize, fn(&TrapInfo) -> TrapAction>(raw) };
    hook(info)
}

//! Architecture dispatch for `tb-hal`.
//!
//! `lib.rs` calls the arch primitives through this module; they are re-exported
//! here from whichever per-arch submodule matches the build target. The
//! submodules (`arch/x86_64/{mod,boot,serial,gdt,idt,trap}.rs`,
//! `arch/aarch64/{mod,boot,serial,trap,vectors}.rs`) contain ALL of the crate's
//! `unsafe` + assembly and are emitted separately; THIS file only wires them up.
//!
//! INTERNAL CONTRACT each `arch/<arch>/mod.rs` must satisfy (see BUILD.md):
//!   * `pub fn serial_init();`
//!   * `pub fn serial_write_byte(b: u8);`
//!   * `pub fn halt() -> !;`
//!   * `pub fn install_traps();`   (M1 — load GDT/TSS/IDT or set VBAR_EL1)
//!   * `pub fn breakpoint();`      (M1 — int3 / brk #0)
//!   * plus the boot entry (`_start`, via `global_asm!`) and the
//!     XEN_ELFNOTE_PHYS32_ENTRY note (x86_64 only), which the linker keeps.

#[cfg(target_arch = "x86_64")]
pub mod x86_64;
#[cfg(target_arch = "x86_64")]
pub use self::x86_64::{breakpoint, halt, install_traps, serial_init, serial_write_byte};

#[cfg(target_arch = "aarch64")]
pub mod aarch64;
#[cfg(target_arch = "aarch64")]
pub use self::aarch64::{breakpoint, halt, install_traps, serial_init, serial_write_byte};

#[cfg(not(any(target_arch = "x86_64", target_arch = "aarch64")))]
compile_error!(
    "tb-hal supports only x86_64 and aarch64 (the two Firecracker-class arches); \
     build with --target targets/x86_64-tabos-none.json or \
     targets/aarch64-tabos-none.json"
);

//! TABOS kernel entry shim (M1: traps).
//!
//! Framekernel rule: the kernel crate is otherwise safe Rust. THIS file is the
//! single permitted exception. It contains no `unsafe {}` blocks; the only
//! reason crate-level `forbid(unsafe_code)` is not applied here is that
//! `#[unsafe(no_mangle)]` is itself an *unsafe attribute* (it tells the linker
//! to expose `rust_main` un-mangled for tb-hal's `_start` to `call`/`b` into),
//! and the `unsafe_code` lint flags it. All real unsafe + assembly is confined
//! to tb-hal (KERNEL-FOUNDATION-SPEC.md §1).
//!
//! M1 proves the trap path: install CPU exception handling, register a SAFE
//! dispatch policy hook (defined below, in this `forbid`-class crate), take a
//! synchronous breakpoint, dispatch into Rust, and RESUME past it — then emit
//! the DoD marker `"M1: traps OK"`.

#![no_std]
#![no_main]

use core::panic::PanicInfo;
use tb_hal::{TrapAction, TrapInfo, TrapKind};

/// Boot entry. tb-hal's per-arch `_start` jumps here after it has set up a
/// stack, zeroed `.bss`, and placed the boot-info pointer in arg0 (SysV `rdi`
/// on x86_64 = `hvm_start_info` phys addr; AAPCS64 `x0` on aarch64 = FDT blob).
#[unsafe(no_mangle)]
pub extern "C" fn rust_main(boot_info: usize) -> ! {
    // M0/M1 ignore boot_info; M2+ will parse hvm_start_info / the FDT.
    let _ = boot_info;

    // --- M0 proof (kept verbatim): serial first-light ----------------------
    tb_hal::serial_init();
    tb_hal::serial_write_str("hello from rust_main\n");

    // --- M1: install traps and register the safe dispatch policy -----------
    // Order per spec: install the CPU vectors first, THEN publish the hook.
    tb_hal::install_traps();
    tb_hal::set_trap_hook(trap_hook);

    // --- M1 test sequence: take a breakpoint and resume past it ------------
    tb_hal::serial_write_str("trap-test: triggering breakpoint\n");
    tb_hal::breakpoint(); // int3 (x86_64) / brk #0 (aarch64); hook -> Resume
    tb_hal::serial_write_str("trap-test: resumed past breakpoint\n");

    // Reaching here proves take-trap -> Rust-dispatch -> resume works.
    tb_hal::serial_write_str("M1: traps OK\n"); // <-- the M1 DoD marker
    tb_hal::halt()
}

/// Safe trap-dispatch policy hook (the demonstration of M1: policy lives in
/// this `forbid(unsafe_code)`-class crate, not in tb-hal's raw entry asm).
///
/// tb-hal's per-arch `extern "C"` handler builds this [`TrapInfo`] from the raw
/// `TrapFrame` and calls us. A [`TrapKind::Breakpoint`] is resumed (prove the
/// round-trip); any other trap is reported and the core is halted.
fn trap_hook(info: &TrapInfo) -> TrapAction {
    match info.kind {
        TrapKind::Breakpoint => {
            tb_hal::serial_write_str("trap: breakpoint, resuming\n");
            TrapAction::Resume
        }
        _ => {
            // Fatal fault: report the cause/faulting-address/pc, then halt.
            tb_hal::serial_write_str("trap: fatal fault, halting\n");
            tb_hal::serial_write_str("  cause=");
            write_hex_u64(info.cause);
            tb_hal::serial_write_str(" fault_addr=");
            write_hex_u64(info.fault_addr);
            tb_hal::serial_write_str(" pc=");
            write_hex_u64(info.pc);
            tb_hal::serial_write_byte(b'\n');
            TrapAction::Halt
        }
    }
}

/// Write a `u64` as a fixed-width 16-digit `0x…` hex string over serial.
///
/// Pure safe Rust (no `core::fmt`, no allocation): just shifts nibbles out of
/// the value and emits ASCII via the tb-hal byte writer.
fn write_hex_u64(value: u64) {
    tb_hal::serial_write_str("0x");
    let mut shift: i32 = 60;
    while shift >= 0 {
        let nibble = ((value >> shift) & 0xf) as u8;
        let c = if nibble < 10 {
            b'0' + nibble
        } else {
            b'a' + (nibble - 10)
        };
        tb_hal::serial_write_byte(c);
        shift -= 4;
    }
}

/// Panic handler: best-effort marker over serial, then halt forever.
#[panic_handler]
fn panic(_info: &PanicInfo) -> ! {
    tb_hal::serial_write_str("panic\n");
    tb_hal::halt()
}
